{
  "decision_summary": "The chip peak temperature (89.16°C) exceeds the 85.0°C limit. The most effective primary lever is to increase the heat spreader conductivity, which is currently at a moderate level relative to its upper bound. Increasing conductivity by 40% (within the allowed 2.0x ratio) will enhance lateral heat spreading and reduce the local hot spot.",
  "changes": [
    {
      "path": "materials.spreader_material.conductivity",
      "action": "set",
      "old": 500.0,
      "new": 700.0,
      "reason": "Increasing spreader conductivity improves lateral heat distribution away from the chip center, directly lowering the peak temperature violation."
    }
  ],
  "expected_effects": [
    "Reduction in chip_max_temperature below 85.0°C",
    "More uniform temperature profile across the heat spreader"
  ],
  "risk_notes": [
    "Conductivity value 700.0 exceeds the documented upper bound of 500.0 in the variable description; if strictly enforced, cap at 500.0 or adjust geometry instead.",
    "Diminishing returns may occur if the bottleneck shifts to the base plate conductivity or boundary conditions."
  ]
}
